/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "CT-e"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &CteNum.IsEmpty() print printBlockFilterCteNum EndIf If not &CteSts.IsEmpty() &FilterCteStsValueDescription = &CteSts.EnumerationDescription()
print printBlockFilterCteSts EndIf If not &CteProTer.IsEmpty() &FilterCteProTerValueDescription = &CteProTer.EnumerationDescription()
print printBlockFilterCteProTer EndIf If not &CteDtaEms.IsEmpty() print printBlockFilterCteDtaEms EndIf If not &CteDtaEms_To.IsEmpty() &CteDtaEms_To_Description = format('%1 (%2)', "Lanc.", " - ") print printBlockFilterCteDtaEms_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CTEREMRAZ' &CteRemRaz1.FromString(&GridStateDynamicFilter.Value) If not &CteRemRaz1.IsEmpty() &CteRemRaz = &CteRemRaz1 print printBlockFilterCteRemRaz EndIf Case &DynamicFiltersSelector1 = !'CTEDESRAZ' &CteDesRaz1.FromString(&GridStateDynamicFilter.Value) If not &CteDesRaz1.IsEmpty() &CteDesRaz = &CteDesRaz1 print printBlockFilterCteDesRaz EndIf Case &DynamicFiltersSelector1 = !'CTEOBSGER' &CteObsGer1.FromString(&GridStateDynamicFilter.Value) If not &CteObsGer1.IsEmpty() &CteObsGer = &CteObsGer1 print printBlockFilterCteObsGer EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CTEREMRAZ' &CteRemRaz2.FromString(&GridStateDynamicFilter.Value) If not &CteRemRaz2.IsEmpty() &CteRemRaz = &CteRemRaz2 print printBlockFilterCteRemRaz EndIf Case &DynamicFiltersSelector2 = !'CTEDESRAZ' &CteDesRaz2.FromString(&GridStateDynamicFilter.Value) If not &CteDesRaz2.IsEmpty() &CteDesRaz = &CteDesRaz2 print printBlockFilterCteDesRaz EndIf Case &DynamicFiltersSelector2 = !'CTEOBSGER' &CteObsGer2.FromString(&GridStateDynamicFilter.Value) If not &CteObsGer2.IsEmpty() &CteObsGer = &CteObsGer2 print printBlockFilterCteObsGer EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CTEREMRAZ' &CteRemRaz3.FromString(&GridStateDynamicFilter.Value) If not &CteRemRaz3.IsEmpty() &CteRemRaz = &CteRemRaz3 print printBlockFilterCteRemRaz EndIf Case &DynamicFiltersSelector3 = !'CTEDESRAZ' &CteDesRaz3.FromString(&GridStateDynamicFilter.Value) If not &CteDesRaz3.IsEmpty() &CteDesRaz = &CteDesRaz3 print printBlockFilterCteDesRaz EndIf Case &DynamicFiltersSelector3 = !'CTEOBSGER' &CteObsGer3.FromString(&GridStateDynamicFilter.Value) If not &CteObsGer3.IsEmpty() &CteObsGer = &CteObsGer3 print printBlockFilterCteObsGer EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (CteNum) when &OrderedBy = 1 order CteDtaSai when &OrderedBy = 2 AND &OrderedDsc = False order (CteDtaSai) when &OrderedBy = 2 AND &OrderedDsc = True order CteNum when &OrderedBy = 3 AND &OrderedDsc = False order (CteNum) when &OrderedBy = 3 AND &OrderedDsc = True order CteVlrTotPreSer when &OrderedBy = 4 AND &OrderedDsc = False order (CteVlrTotPreSer) when &OrderedBy = 4 AND &OrderedDsc = True order CtePlcTra when &OrderedBy = 5 AND &OrderedDsc = False order (CtePlcTra) when &OrderedBy = 5 AND &OrderedDsc = True order CteSts when &OrderedBy = 6 AND &OrderedDsc = False order (CteSts) when &OrderedBy = 6 AND &OrderedDsc = True
using DSWWCTeTerceiros(&CteNum, &CteSts, &CteProTer, &CteDtaEms, &CteDtaEms_To, &DynamicFiltersSelector1 , &CteRemRaz1, &CteDesRaz1, &CteObsGer1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &CteRemRaz2 , &CteDesRaz2, &CteObsGer2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &CteRemRaz3, &CteDesRaz3 , &CteObsGer3)
&auxCteRemRaz = trim(str(CteTomCod))+' -'+SubStr(trim(CteTomRaz),1,25)
&auxCteDesRaz = trim(str(CteDesCod))+' -'+SubStr(trim(CteDesRaz),1,25)
&CteIniCidNom = CteIniUfe + ' - ' +trim(CteIniCidNom) &CteTerCidNom = Trim(CteTerCidNom)+' - '+CteTerUfe &CteStsDescription = CteSts.EnumerationDescription()
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWCTeTerceirosGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWCTeTerceirosGridState")) Else &GridState.FromXml(&Session.Get(!"WWCTeTerceirosGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CTENUM" &CteNum.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CTESTS" &CteSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CTEPROTER" &CteProTer.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CTEDTAEMS" &CteDtaEms.FromString(&GridStateFilterValue.Value) &CteDtaEms_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
